}

return json(object(
        field("id", rawProfile.sub),
        field("displayName", rawProfile.name),
        field("photoUrl", rawProfile.picture),
        field("email", email),
        fieldIfNotNull("givenName", firstName),
        fieldIfNotNull("familyName", lastName),
        field("username", username)))

